module top_module (
    input r,
    input m,
    output reg output_flag
);
    always @(*) begin
        case ({r, m})
            2'b00: output_flag = 1'b0;
            2'b01: output_flag = 1'b0;
            2'b11: output_flag = 1'b0;
            2'b10: output_flag = 1'b1;
        endcase
    end
endmodule
